"use strict";(self.webpackChunkmy_website=self.webpackChunkmy_website||[]).push([[189],{4635:e=>{e.exports=JSON.parse('{"blogPosts":[{"id":"/2026/04/13/_1.1.0","metadata":{"permalink":"/obsidiosaurus-docs/de/release_notes/2026/04/13/_1.1.0","source":"@site/release_notes__blog/2026-04-13_1.1.0.md","title":"v1.1.0 \u2014 New Formatting Features","description":"v1.1.0 adds support for three Obsidian formatting features that were previously not converted.","date":"2026-04-13T00:00:00.000Z","formattedDate":"13. April 2026","tags":[],"readingTime":0.835,"hasTruncateMarker":false,"authors":[],"frontMatter":{},"nextItem":{"title":"v1.0.0 \u2014 Modernization","permalink":"/obsidiosaurus-docs/de/release_notes/2026/04/12/_1.0.0"}},"content":"v1.1.0 adds support for three Obsidian formatting features that were previously not converted.\\n\\n## What\'s new\\n\\n### Comment Filter\\nObsidian comments (`%% ... %%`) are now stripped during conversion \u2014 both inline and multi-line block comments.\\n\\n```\\n%% This will not appear on the website %%\\n\\n%%\\nNeither will this\\nmulti-line block\\n%%\\n```\\n\\n### Highlighting\\n`==highlighted text==` is converted to `<mark>highlighted text</mark>`, which renders with native browser highlight styling.\\n\\n### Mermaid Diagrams\\nMermaid code blocks are passed through to Docusaurus. Requires `@docusaurus/theme-mermaid` in your Docusaurus config:\\n\\n```js\\nthemes: [\'@docusaurus/theme-mermaid\'],\\nmarkdown: { mermaid: true }\\n```\\n\\nSupported diagram types: flowchart, sequence, class, gantt, pie \u2014 and all other Mermaid types.\\n\\n### Already working (no conversion needed)\\n- Footnotes (`[^1]`) \u2014 handled natively by MDX\\n- Task lists (`- [ ]` / `- [x]`) \u2014 handled natively by MDX\\n\\n## Bug Fix\\n- `<mark>` at the start of a line is now prefixed with `{\'\'}` to prevent MDX 2 from parsing the paragraph as a block-level JSX element"},{"id":"/2026/04/12/_1.0.0","metadata":{"permalink":"/obsidiosaurus-docs/de/release_notes/2026/04/12/_1.0.0","source":"@site/release_notes__blog/2026-04-12_1.0.0.md","title":"v1.0.0 \u2014 Modernization","description":"After a long hiatus from the original project, v1.0.0 is a full modernization of the codebase \u2014 same feature set, rebuilt foundation.","date":"2026-04-12T00:00:00.000Z","formattedDate":"12. April 2026","tags":[],"readingTime":1.005,"hasTruncateMarker":false,"authors":[],"frontMatter":{},"prevItem":{"title":"v1.1.0 \u2014 New Formatting Features","permalink":"/obsidiosaurus-docs/de/release_notes/2026/04/13/_1.1.0"},"nextItem":{"title":"v0.3.0","permalink":"/obsidiosaurus-docs/de/release_notes/2023/07/01/_0.3"}},"content":"After a long hiatus from the original project, v1.0.0 is a full modernization of the codebase \u2014 same feature set, rebuilt foundation.\\n\\n## What\'s new\\n\\n### Codebase\\n- TypeScript upgraded from 4.7 to 5.4\\n- `mainProcessor.ts` refactored from 1021 lines into dedicated modules: `fileScanner.ts`, `fileInfoBuilder.ts`, `changeTracker.ts`, `assetProcessor.ts`\\n- pino logger replaced with `console` (no more Node-only dependency in Electron)\\n- GraphicsMagick (`gm`) replaced with Canvas API \u2014 no system dependency required\\n- `augmentPathForMacOS()` removed \u2014 cross-platform by default\\n\\n### Docusaurus v3 Compatibility\\n- Output changed from `.md` to `.mdx`\\n- Admonition syntax updated to v3 format: `:::note[Title]`\\n- `future: { v4: true }` compatible \u2014 `.md` treated as CommonMark, `.mdx` as MDX\\n\\n### Bug Fixes\\n- **#13 / #18** \u2014 Asset filenames with leading digits were corrupted during sanitization\\n- **#14** \u2014 ENOENT crash when copying assets for modified files (stale `assetJson` entries)\\n- **#16** \u2014 Renamed files left orphan pages in the output\\n- `[!QUOTE]` callout now correctly converted to blockquote\\n\\n### Plugin Setup\\n- `vaultPath` is now read dynamically from Obsidian (`vault.adapter.getBasePath()`) \u2014 no more hardcoded `\\"vault\\"` folder name\\n- Released as BRAT-installable plugin with `main.js`, `manifest.json`, `styles.css` attached\\n\\n### Tests\\n- 33 tests covering `markdownProcessor`, `fileInfoBuilder`, `changeTracker`, `assetProcessor`"},{"id":"/2023/07/01/_0.3","metadata":{"permalink":"/obsidiosaurus-docs/de/release_notes/2023/07/01/_0.3","source":"@site/release_notes__blog/2023-07-01_0.3.md","title":"v0.3.0","description":"I am excited to announce the first preview version of Obsidiosaurus  as Plugin for Obsidian.md","date":"2023-07-01T00:00:00.000Z","formattedDate":"1. Juli 2023","tags":[],"readingTime":0.725,"hasTruncateMarker":false,"authors":[],"frontMatter":{},"prevItem":{"title":"v1.0.0 \u2014 Modernization","permalink":"/obsidiosaurus-docs/de/release_notes/2026/04/12/_1.0.0"}},"content":"I am excited to announce the first preview version of **Obsidiosaurus ** as Plugin for Obsidian.md\\n\\nTest\\n## What is currently supported?\\n\\n### General\\n- Documentation: \u2705\\n- Blog: \u2705 \\n- Multiple Blogs: \u2705 \\n- Localisation i18n: \u2705\\n- Multiple Sidebars: \u2705\\n\\n### Standard Formating\\n- Links: \u2705\\n- Tables: \u2705\\n- Admonitions/Callouts: \u2705\\n- Quotes: \u2705\\n- iFrames: \u2705\\n- Codeblocks: \u2705\\n- Head Metadata: \u2705\\n- Checklists: \u2705\\n\\n### Assets\\n- Images: \u2705 (.png & .svg)\\n  - Image resize: \u2705\\n  - Image converter: \u2705 (.webp) \\n- File download: \u2705 (.pdf, .docx, ..)\\n\\n### Drawings & Diagrams\\n- Excalidraw: \u2705 (light & dark mode)\\n- diagrams.net \u2705 (light & dark mode)\\n- Math Equations: \u2705 (with [Docusaurus Plugin)](https://docusaurus.io/docs/markdown-features/math-equations#usage)\\n- Mermaid: \u2705 (with [Docusaurus Plugin)](https://docusaurus.io/docs/markdown-features/diagrams#configuration)\\n\\n\\n## Known Issues:\\nWhen renaming files and folders in Obsidian, it doesn\'t delete the outdated files from your Docusaurus files."}]}')}}]);